      ptr_next[offset + k] = 0.0f;

      ptr_vel[offset + k] = 2250000.0f;
    }
  }

  for (int s = 11; s >= 0; s--) {
    for (size_t i = nRows / 2 - s; i < nRows / 2 + s; i++) {
      size_t offset = i * nCols;
